protected void insertInventAgingStorage(InventAgingStorageContract _dataContract)
{
     InventAgingStorage          inventAgingStorage;
     CreatedTransactionId        createdTransactionId;
     InventAgingTmp              localLine;
     InventDim                   inventdimloc;
     InventBatch                 inventbatch;
     InventAgingStorage          inventAgingStorageloc;
     FinancialDimensionSetEntity financialDimensionSetEntity;
     DimensionAttributeValue     dimensionAttributeValue;
     DimensionDefault            defaultDimension;
     DimensionAttribute          dimensionAttribute;
     InventTrans                 inventTransloc, inventTransissue;
     InventTransPosting          inventTransPosting;
     InventTransOrigin           inentTransOrigin;

     next insertInventAgingStorage(_dataContract);

     createdTransactionId = this.parmCreatedTransactionId();

     select forupdate inventAgingStorage
         where inventAgingStorage.TransactionId == createdTransactionId;

     if (inventAgingStorage && inventAgingStorage.TransactionId)
     {
         ttsbegin;
         inventAgingStorage.DimensionSetName = _dataContract.parmFinancialDimSet();
         inventAgingStorage.update();
         ttscommit;
     }

     DimensionAttributeValueSetStorage   valueSetStorage = new DimensionAttributeValueSetStorage();

     while select forupdate localLine 
         where localLine.CreatedTransactionId == inventAgingStorage.TransactionId
     {

         //defaultDimension  =   InventTable::find(localLine.ItemId).defaultdimension;

         select * from inventTransloc 
             where inventTransloc.ItemId == localLine.ItemId
             && inventTransissue.StatusReceipt == StatusReceipt::Purchased
         join inventdimloc
             where  inventdimloc.inventDimId == inventTransloc.inventDimId
                 && inventdimloc.inventBatchId == localLine.inventBatchId
         join inentTransOrigin
             where inentTransOrigin.RecId == inventTransloc.InventTransOrigin
         join  inventTransPosting
             where inventTransPosting.InventTransOrigin == inentTransOrigin.RecId;

         defaultDimension  =   inventTransPosting.defaultdimension;

         //select firstonly inventTransPosting
         //join inventTransOrigin
         // where InventTransOrigin.RecId == inventTransPosting.InventTransOrigin
         //    && InventTransOrigin.ItemId == localLine.ItemId;

         //select * from  inventTransissue
         //    where inventTransissue.InventTransOrigin == inventTransOrigin.RecId
         //    && inventTransissue.StatusReceipt == StatusReceipt::Purchased
         //join inventdimloc
         //    where inventdimloc.inventDimId == InventTransOrigin.ItemInventDimId
         //        && inventdimloc.inventBatchId == _inventDim.inventBatchId;


         select firstonly financialDimensionSetEntity
         where financialDimensionSetEntity.Name == inventAgingStorage.DimensionSetName;

         if (financialDimensionSetEntity.SegmentName01)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName01);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName01),false,false);
         if (dimensionAttributeValue)
             valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName02)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName02);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName02),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName03)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName03);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName03),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName04)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName04);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName04),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName05)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName05);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName05),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName06)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName06);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName06),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName07)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName07);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName07),false,false);
         if (dimensionAttributeValue)
             valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName08)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName08);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName08),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName09)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName09);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName09),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName10)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName10);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName10),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }
         if (financialDimensionSetEntity.SegmentName11)
         {
             dimensionAttribute = dimensionAttribute::findByName(financialDimensionSetEntity.SegmentName11);
             dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,localLine.getFinDimValue(defaultDimension, financialDimensionSetEntity.SegmentName11),false,false);
             if (dimensionAttributeValue)
         valueSetStorage.addItem(dimensionAttributeValue);
         }

         if (localLine)
         {
             ttsbegin;
             localLine.DefaultDimension = valueSetStorage.save();
             localLine.update();
             ttscommit;
         }
     }


 }
